s3_client = boto3.client('s3')
dynamodb = boto3.resource('dynamodb')
sns_client = boto3.client('sns')
sqs_client = boto3.client('sqs')

def lambda_handler(event, context):
    function_name = context.function_name
    request_id = context.request_id
    
    try:
        print(f"Function: {function_name}, RequestId: {request_id}")
        print(f"Event: {json.dumps(event)}")
        
        event_type = event.get('eventType', 'unknown')
        
        if event_type == 's3_operation':
            result = handle_s3_operation(event)
        elif event_type == 'dynamodb_operation':
            result = handle_dynamodb_operation(event)
        elif event_type == 'sns_operation':
            result = handle_sns_operation(event)
        elif event_type == 'sqs_operation':
            result = handle_sqs_operation(event)
        else:
            result = handle_generic_operation(event)
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Operation completed successfully',
                'result': result,
                'functionName': function_name,
                'requestId': request_id,
                'timestamp': datetime.utcnow().isoformat()
            })
        }
        
    except Exception as e:
        print(f"Error in {function_name}: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps({
                'message': 'Operation failed',
                'error': str(e),
                'functionName': function_name,
                'requestId': request_id,
                'timestamp': datetime.utcnow().isoformat()
            })
        }

def handle_s3_operation(event):
    bucket = event.get('bucket')
    key = event.get('key')
    operation = event.get('operation', 'get')
    
    if operation == 'get':
        response = s3_client.get_object(Bucket=bucket, Key=key)
        content = response['Body'].read().decode('utf-8')
        return {'operation': 'get', 'content_length': len(content)}
    
    elif operation == 'put':
        data = event.get('data', '')
        s3_client.put_object(Bucket=bucket, Key=key, Body=data)
        return {'operation': 'put', 'key': key}
    
    elif operation == 'list':
        response = s3_client.list_objects_v2(Bucket=bucket, Prefix=key)
        objects = [obj['Key'] for obj in response.get('Contents', [])]
        return {'operation': 'list', 'count': len(objects), 'objects': objects}
    
    return {'operation': operation, 'status': 'completed'}

def handle_dynamodb_operation(event):
    table_name = event.get('table')
    operation = event.get('operation', 'get')
    
    table = dynamodb.Table(table_name)
    
    if operation == 'get':
        key = event.get('key')
        response = table.get_item(Key=key)
        return {'operation': 'get', 'item': response.get('Item')}
    
    elif operation == 'put':
        item = event.get('item')
        table.put_item(Item=item)
        return {'operation': 'put', 'success': True}
    
    elif operation == 'query':
        key_condition = event.get('keyCondition')
        response = table.query(KeyConditionExpression=key_condition)
        return {'operation': 'query', 'count': response['Count'], 'items': response['Items']}
    
    elif operation == 'scan':
        response = table.scan(Limit=event.get('limit', 100))
        return {'operation': 'scan', 'count': response['Count'], 'items': response['Items']}
    
    return {'operation': operation, 'status': 'completed'}

def handle_sns_operation(event):
    topic_arn = event.get('topicArn')
    operation = event.get('operation', 'publish')
    
    if operation == 'publish':
        message = event.get('message')
        subject = event.get('subject', 'Microservice Notification')
        
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=json.dumps(message) if isinstance(message, dict) else message,
            Subject=subject
        )
        return {'operation': 'publish', 'messageId': response['MessageId']}
    
    return {'operation': operation, 'status': 'completed'}

def handle_sqs_operation(event):
    queue_url = event.get('queueUrl')
    operation = event.get('operation', 'send')
    
    if operation == 'send':
        message = event.get('message')
        response = sqs_client.send_message(
            QueueUrl=queue_url,
            MessageBody=json.dumps(message) if isinstance(message, dict) else message
        )
        return {'operation': 'send', 'messageId': response['MessageId']}
    
    elif operation == 'receive':
        response = sqs_client.receive_message(
            QueueUrl=queue_url,
            MaxNumberOfMessages=event.get('maxMessages', 10),
            WaitTimeSeconds=event.get('waitTime', 5)
        )
        messages = response.get('Messages', [])
        return {'operation': 'receive', 'count': len(messages), 'messages': messages}
    
    elif operation == 'delete':
        receipt_handle = event.get('receiptHandle')
        sqs_client.delete_message(QueueUrl=queue_url, ReceiptHandle=receipt_handle)
        return {'operation': 'delete', 'success': True}
    
    return {'operation': operation, 'status': 'completed'}

def handle_generic_operation(event):
    return {
        'message': 'Generic operation handler',
        'event': event,
        'environmentVariables': dict(os.environ)
    }